VIEWPORT_HEIGHT = int(os.environ.get("VIEWPORT_HEIGHT", "1080"))
SCREENSHOT_TIMEOUT = int(os.environ.get("SCREENSHOT_TIMEOUT", "30"))
CACHE_TTL_HOURS = int(os.environ.get("CACHE_TTL_HOURS", "24"))
MAX_URL_LENGTH = 2048
ALLOWED_SCHEMES = {"http", "https"}
BLOCKED_HOSTS = {"localhost", "127.0.0.1", "0.0.0.0", "169.254.169.254", "metadata.google.internal"}

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Initialize S3 client
s3_client = boto3.client("s3", region_name=AWS_REGION)


def validate_url(url: str) -> tuple[bool, str]:
    """Validate the provided URL for security and correctness."""
    if not url:
        return False, "URL is required"
    
    if len(url) > MAX_URL_LENGTH:
        return False, f"URL exceeds maximum length of {MAX_URL_LENGTH} characters"
    
    try:
        parsed = urlparse(url)
    except Exception:
        return False, "Invalid URL format"
    
    if parsed.scheme not in ALLOWED_SCHEMES:
        return False, f"URL scheme must be one of: {', '.join(ALLOWED_SCHEMES)}"
    
    if not parsed.netloc:
        return False, "URL must have a valid hostname"
    
    hostname = parsed.hostname
    if hostname in BLOCKED_HOSTS:
        return False, "Access to this host is not allowed"
    
    # Block private IP ranges
    try:
        import ipaddress
        ip = ipaddress.ip_address(hostname)
        if ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_reserved:
            return False, "Access to private/reserved IP addresses is not allowed"
    except ValueError:
        # Not an IP address, it's a hostname - that's fine
        pass
    
    return True, ""


def generate_cache_key(url: str) -> str:
    """Generate a deterministic cache key for a URL."""
    url_hash = hashlib.sha256(url.encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}{url_hash}"


def check_s3_cache(cache_key: str) -> str | None:
    """Check if a screenshot already exists in S3 and is not expired."""
    try:
        response = s3_client.head_object(Bucket=S3_BUCKET, Key=f"{cache_key}.png")
        last_modified = response["LastModified"]
        age_hours = (datetime.now(last_modified.tzinfo) - last_modified).total_seconds() / 3600
        
        if age_hours < CACHE_TTL_HOURS:
            # Generate presigned URL
            presigned_url = s3_client.generate_presigned_url(
                "get_object",
                Params={"Bucket": S3_BUCKET, "Key": f"{cache_key}.png"},
                ExpiresIn=3600,
            )
            return presigned_url
    except ClientError as e:
        if e.response["Error"]["Code"] == "404":
            return None
        logger.error(f"S3 cache check error: {e}")
    
    return None


def create_chrome_driver() -> webdriver.Chrome:
    """Create and configure a headless Chrome WebDriver instance."""
    chrome_options = Options()
    chrome_options.add_argument("--headless=new")
    chrome_options.add_argument("--no-sandbox")
    chrome_options.add_argument("--disable-dev-shm-usage")
    chrome_options.add_argument("--disable-gpu")
    chrome_options.add_argument("--disable-extensions")
    chrome_options.add_argument("--disable-software-rasterizer")
    chrome_options.add_argument(f"--window-size={VIEWPORT_WIDTH},{VIEWPORT_HEIGHT}")
    chrome_options.add_argument("--hide-scrollbars")
    chrome_options.add_argument("--disable-notifications")
    chrome_options.add_argument("--disable-popup-blocking")
    chrome_options.add_argument("--disable-infobars")
    chrome_options.add_argument("--disable-translate")
    chrome_options.add_argument("--disable-background-networking")
    chrome_options.add_argument("--disable-sync")
    chrome_options.add_argument("--disable-default-apps")
    chrome_options.add_argument("--no-first-run")
    chrome_options.add_argument("--single-process")
    chrome_options.add_argument("--user-agent=Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36")
    
    if os.path.exists(CHROME_BINARY_PATH):
        chrome_options.binary_location = CHROME_BINARY_PATH
    
    service = Service(executable_path=CHROME_DRIVER_PATH) if os.path.exists(CHROME_DRIVER_PATH) else Service()
    
    driver = webdriver.Chrome(service=service, options=chrome_options)
    driver.set_page_load_timeout(SCREENSHOT_TIMEOUT)
    driver.set_script_timeout(SCREENSHOT_TIMEOUT)
    
    return driver


def take_screenshot(url: str) -> bytes:
    """Take a screenshot of the given URL using headless Chrome."""
    driver = None
    try:
        driver = create_chrome_driver()
        logger.info(f"Navigating to URL: {url}")
        
        driver.get(url)
        
        # Wait for the page to be in a ready state
        WebDriverWait(driver, SCREENSHOT_TIMEOUT).until(
            lambda d: d.execute_script("return document.readyState") == "complete"
        )
        
        # Additional wait for dynamic content to render
        time.sleep(2)
        
        # Take screenshot
        screenshot_bytes = driver.get_screenshot_as_png()
        
        logger.info(f"Screenshot captured for URL: {url}")
        return screenshot_bytes
    
    except Exception as e:
        logger.error(f"Screenshot capture failed for {url}: {e}")
        raise
    finally:
        if driver:
            try:
                driver.quit()
            except Exception:
                pass


def create_thumbnail(screenshot_bytes: bytes, width: int = THUMBNAIL_WIDTH, height: int = THUMBNAIL_HEIGHT) -> bytes:
    """Create a thumbnail from a full-size screenshot."""
    image = Image.open(io.BytesIO(screenshot_bytes))
    
    # Calculate the crop area (top portion of the page)
    img_width, img_height = image.size
    aspect_ratio = width / height
    
    crop_height = int(img_width / aspect_ratio)
    if crop_height > img_height:
        crop_height = img_height
    
    # Crop from the top
    image = image.crop((0, 0, img_width, crop_height))
    
    # Resize to thumbnail dimensions
    image = image.resize((width, height), Image.LANCZOS)
    
    # Convert to PNG bytes
    buffer = io.BytesIO()
    image.save(buffer, format="PNG", optimize=True)
    buffer.seek(0)
    
    return buffer.read()


def upload_to_s3(image_bytes: bytes, cache_key: str, content_type: str = "image/png") -> str:
    """Upload screenshot to S3 and return a presigned URL."""
    s3_key = f"{cache_key}.png"
    
    try:
        s3_client.put_object(
            Bucket=S3_BUCKET,
            Key=s3_key,
            Body=image_bytes,
            ContentType=content_type,
            CacheControl=f"max-age={CACHE_TTL_HOURS * 3600}",
            Metadata={
                "created_at": datetime.utcnow().isoformat(),
            },
        )
        
        presigned_url = s3_client.generate_presigned_url(
            "get_object",
            Params={"Bucket": S3_BUCKET, "Key": s3_key},
            ExpiresIn=3600,
        )
        
        logger.info(f"Screenshot uploaded to S3: {s3_key}")
        return presigned_url
    
    except ClientError as e:
        logger.error(f"S3 upload failed: {e}")
        raise


def ensure_bucket_exists():
    """Ensure the S3 bucket exists, create if it doesn't."""
    try:
        s3_client.head_bucket(Bucket=S3_BUCKET)
    except ClientError as e:
        error_code = e.response["Error"]["Code"]
        if error_code == "404":
            logger.info(f"Creating S3 bucket: {S3_BUCKET}")
            if AWS_REGION == "us-east-1":
                s3_client.create_bucket(Bucket=S3_BUCKET)
            else:
                s3_client.create_bucket(
                    Bucket=S3_BUCKET,
                    CreateBucketConfiguration={"LocationConstraint": AWS_REGION},
                )
            
            # Enable versioning
            s3_client.put_bucket_versioning(
                Bucket=S3_BUCKET,
                VersioningConfiguration={"Status": "Enabled"},
            )
            
            # Set lifecycle policy to clean up old screenshots
            s3_client.put_bucket_lifecycle_configuration(
                Bucket=S3_BUCKET,
                LifecycleConfiguration={
                    "Rules": [
                        {
                            "ID": "CleanupOldScreenshots",
                            "Filter": {"Prefix": S3_PREFIX},
                            "Status": "Enabled",
                            "Expiration": {"Days": 30},
                            "NoncurrentVersionExpiration": {"NoncurrentDays": 7},
                        }
                    ]
                },
            )
            logger.info(f"S3 bucket created: {S3_BUCKET}")
        else:
            raise


