@app.route("/screenshot", methods=["POST"])
def screenshot():
    """
    Take a screenshot of a URL and return a thumbnail preview.
    
    Request JSON body:
    {
        "url": "https://example.com",
        "width": 600,        # optional, thumbnail width
        "height": 400,       # optional, thumbnail height
        "force_refresh": false  # optional, bypass cache
    }
    
    Response:
    {
        "success": true,
        "url": "https://example.com",
        "screenshot_url": "https://s3-presigned-url...",
        "cached": false,
        "thumbnail_dimensions": {"width": 600, "height": 400}
    }
    """
    data = request.get_json()
    if not data:
        return jsonify({"success": False, "error": "Request body must be JSON"}), 400
    
    url = data.get("url", "").strip()
    width = data.get("width", THUMBNAIL_WIDTH)
    height = data.get("height", THUMBNAIL_HEIGHT)
    force_refresh = data.get("force_refresh", False)
    
    # Validate URL
    is_valid, error_message = validate_url(url)
    if not is_valid:
        return jsonify({"success": False, "error": error_message}), 400
    
    # Validate dimensions
    try:
        width = int(width)
        height = int(height)
        if width < 50 or width > 3840 or height < 50 or height > 2160:
            return jsonify({"success": False, "error": "Dimensions must be between 50 and 3840 (width) / 2160 (height)"}), 400
    except (ValueError, TypeError):
        return jsonify({"success": False, "error": "Invalid dimensions"}), 400
    
    cache_key = generate_cache_key(url)
    
    # Check cache unless force refresh
    if not force_refresh:
        cached_url = check_s3_cache(cache_key)
        if cached_url:
            logger.info(f"Cache hit for URL: {url}")
            return jsonify({
                "success": True,
                "url": url,
                "screenshot_url": cached_url,
                "cached": True,
                "thumbnail_dimensions": {"width": width, "height": height},
            })
    
    try:
        # Take screenshot
        screenshot_bytes = take_screenshot(url)
        
        # Create thumbnail
        thumbnail_bytes = create_thumbnail(screenshot_bytes, width, height)
        
        # Upload to S3
        screenshot_url = upload_to_s3(thumbnail_bytes, cache_key)
        
        return jsonify({
            "success": True,
            "url": url,
            "screenshot_url": screenshot_url,
            "cached": False,
            "thumbnail_dimensions": {"width": width, "height": height},
        })
    
    except Exception as e:
        logger.error(f"Failed to process screenshot for {url}: {e}")
        return jsonify({
            "success": False,
            "error": f"Failed to capture screenshot: {str(e)}",
        }), 500


