@app.route("/screenshot/image", methods=["GET"])
def screenshot_image():
    """
    Directly return the screenshot image (useful for embedding in <img> tags).
    Query parameters: url, width, height
    """
    url = request.args.get("url", "").strip()
    width = int(request.args.get("width", THUMBNAIL_WIDTH))
    height = int(request.args.get("height", THUMBNAIL_HEIGHT))
    
    is_valid, error_message = validate_url(url)
    if not is_valid:
        return jsonify({"success": False, "error": error_message}), 400
    
    cache_key = generate_cache_key(url)
    
    # Try to get from S3 cache
    try:
        response = s3_client.get_object(Bucket=S3_BUCKET, Key=f"{cache_key}.png")
        last_modified = response["LastModified"]
        age_hours = (datetime.now(last_modified.tzinfo) - last_modified).total_seconds() / 3600
        
        if age_hours < CACHE_TTL_HOURS:
            image_data = response["Body"].read()
            return send_file(
                io.BytesIO(image_data),
                mimetype="image/png",
                download_name="screenshot.png",
            )
    except ClientError:
        pass
    
    try:
        screenshot_bytes = take_screenshot(url)
        thumbnail_bytes = create_thumbnail(screenshot_bytes, width, height)
        upload_to_s3(thumbnail_bytes, cache_key)
        
        return send_file(
            io.BytesIO(thumbnail_bytes),
            mimetype="image/png",
            download_name="screenshot.png",
        )
    
    except Exception as e:
        logger.error(f"Failed to process screenshot for {url}: {e}")
        return jsonify({"success": False, "error": str(e)}), 500


@app.route("/batch", methods=["POST"])
def batch_screenshots():
    """
    Take screenshots of multiple URLs.
    
    Request JSON body:
    {
        "urls": ["https://example1.com", "https://example2.com"],
        "width": 600,
        "height": 400
    }
    """
    data = request.get_json()
    if not data:
        return jsonify({"success": False, "error": "Request body must be JSON"}), 400
    
    urls = data.get("urls", [])
    width = data.get("width", THUMBNAIL_WIDTH)
    height = data.get("height", THUMBNAIL_HEIGHT)
    
    if not urls:
        return jsonify({"success": False, "error": "At least one URL is required"}), 400
    
    if len(urls) > 10:
        return jsonify({"success": False, "error": "Maximum 10 URLs per batch request"}), 400
    
    results = []
    
    for url in urls:
        url = url.strip()
        is_valid, error_message = validate_url(url)
        
        if not is_valid:
            results.append({
                "url": url,
                "success": False,
                "error": error_message,
            })
            continue
        
        cache_key = generate_cache_key(url)
        
        # Check cache
        cached_url = check_s3_cache(cache_key)
        if cached_url:
            results.append({
                "url": url,
                "success": True,
                "screenshot_url": cached_url,
                "cached": True,
            })
            continue
        
        try:
            screenshot_bytes = take_screenshot(url)
            thumbnail_bytes = create_thumbnail(screenshot_bytes, width, height)
            screenshot_url = upload_to_s3(thumbnail_bytes, cache_key)
            
            results.append({
                "url": url,
                "success": True,
                "screenshot_url": screenshot_url,
                "cached": False,
            })
        except Exception as e:
            logger.error(f"Batch screenshot failed for {url}: {e}")
            results.append({
                "url": url,
                "success": False,
                "error": str(e),
            })
    
    success_count = sum(1 for r in results if r.get("success"))
    
    return jsonify({
        "success": True,
        "total": len(urls),
        "successful": success_count,
        "failed": len(urls) - success_count,
        "results": results,
    })


@app.route("/cache/invalidate", methods=["POST"])
def invalidate_cache():
    """
    Invalidate cached screenshot for a URL.
    
    Request JSON body:
    {
        "url": "https://example.com"
    }
    """
    data = request.get_json()
    if not data:
        return jsonify({"success": False, "error": "Request body must be JSON"}), 400
    
    url = data.get("url", "").strip()
    
    is_valid, error_message = validate_url(url)
    if not is_valid:
        return jsonify({"success": False, "error": error_message}), 400
    
    cache_key = generate_cache_key(url)
    
    try:
        s3_client.delete_object(Bucket=S3_BUCKET, Key=f"{cache_key}.png")
        return jsonify({
            "success": True,
            "url": url,
            "message": "Cache invalidated successfully",
        })
    except ClientError as e:
        logger.error(f"Cache invalidation failed: {e}")
        return jsonify({"success": False, "error": str(e)}), 500


